#include<bits/stdc++.h>
using namespace std;
    long long n,a,b,c,mod=1e9+7,der[300001];
long long dfs(long long x){
	if(x<=c)return 1;
	if(der[x]!=0) return der[x];
	return der[x]=(dfs(x-a)%mod+dfs(x-b)%mod)%mod;
}
int main(){

    cin>>n>>a>>b>>c;
    cout<<dfs(n);
    return 0;
}
